const raw = $json || {};
const isObj = (v) => v && typeof v === 'object' && !Array.isArray(v);
const body = isObj(raw.body) ? raw.body : raw;
const headers = isObj(raw.headers) ? raw.headers : {};

const expectedToken = String($env.N8N_WEBHOOK_TOKEN || '').trim();
const hasWebhookShape = !!raw.body || Object.keys(headers).length > 0;
const isSchedule = !hasWebhookShape;

if (hasWebhookShape) {
  const headerToken = String(headers['x-govchat-token'] || headers['X-Govchat-Token'] || '').trim();
  const authHeader = String(headers.authorization || headers.Authorization || '').trim();
  const bearerToken = authHeader.toLowerCase().startsWith('bearer ')
    ? authHeader.slice(7).trim()
    : '';
  const suppliedToken = headerToken || bearerToken;

  if (!expectedToken) throw new Error('Server misconfiguratie: N8N_WEBHOOK_TOKEN ontbreekt');
  if (!suppliedToken || suppliedToken !== expectedToken) throw new Error('Unauthorized webhook token');
}

const runId = String(body.run_id || '').trim() || crypto.randomUUID();
const trigger = isSchedule ? 'schedule' : String(body.trigger || 'manual').trim() || 'manual';
const requestedBy = String(body.requested_by || (isSchedule ? 'n8n-schedule' : 'overlay-admin')).trim();

return [{
  json: {
    run_id: runId,
    trigger,
    requested_by: requestedBy,
    requested_at: new Date().toISOString(),
  },
}];

const run = $('Prepare Crawler Run').first().json || {};
const cfg = $json || {};
const nowIso = new Date().toISOString();

function toHost(u) {
  try { return new URL(u).hostname.toLowerCase(); } catch { return ''; }
}

const allSources = Array.isArray(cfg.sources) ? cfg.sources : [];
const enabledSources = allSources.filter((s) => s && s.enabled !== false);
const enabledSourceIds = enabledSources.map((s) => String(s.id || s.name || s.start_url || '').trim()).filter(Boolean);

if (cfg.enabled === false || enabledSources.length === 0) {
  const skipReason = cfg.enabled === false ? 'Crawler staat uit' : 'Geen actieve bronnen geconfigureerd';
  return [{
    json: {
      ...run,
      crawler_config: cfg,
      skip_run: true,
      skip_reason: skipReason,
      started_at: nowIso,
      finished_at: nowIso,
      summary: {
        visited_pages: 0,
        discovered_links: 0,
        robots_blocked: 0,
        outside_allowlist: 0,
        fetch_errors: 0,
        indexed_items: 0,
        diagnostics: {
          skip_reason: skipReason,
          cfg_enabled: cfg.enabled !== false,
          configured_sources: allSources.length,
          enabled_sources: enabledSources.length,
          enabled_source_ids: enabledSourceIds,
        },
      },
      error: skipReason,
    },
  }];
}

for (const s of enabledSources) {
  if (!Array.isArray(s.allowed_domains) || !s.allowed_domains.length) {
    const h = toHost(s.start_url);
    s.allowed_domains = h ? [h] : [];
  }
  if (!Array.isArray(s.allowed_path_prefixes) || !s.allowed_path_prefixes.length) {
    s.allowed_path_prefixes = ['/'];
  }
  s.max_pages = Math.max(1, Number.parseInt(String(s.max_pages || cfg.max_pages_per_run || 75), 10) || 75);
  s.max_depth = Math.max(1, Number.parseInt(String(s.max_depth || cfg.max_depth || 3), 10) || 3);
}

return [{
  json: {
    ...run,
    crawler_config: cfg,
    sources: enabledSources,
    skip_run: false,
    started_at: nowIso,
    summary: {
      ...(run.summary || {}),
      diagnostics: {
        cfg_enabled: cfg.enabled !== false,
        configured_sources: allSources.length,
        enabled_sources: enabledSources.length,
        enabled_source_ids: enabledSourceIds,
      },
    },
  },
}];

const input = $json || {};
const cfg = input.crawler_config || {};
const sources = Array.isArray(input.sources) ? input.sources : [];

const timeoutMs = Math.max(3000, Number.parseInt(String(cfg.request_timeout_ms || 15000), 10) || 15000);
const maxPagesGlobal = Math.max(10, Number.parseInt(String(cfg.max_pages_per_run || 200), 10) || 200);
const respectRobots = cfg.respect_robots_txt !== false;
const userAgent = String(cfg.user_agent || 'GovChatCrawler/1.0 (+https://govchat.nl)').trim() || 'GovChatCrawler/1.0 (+https://govchat.nl)';
const includeFileTypes = Array.isArray(cfg.include_file_types) && cfg.include_file_types.length
  ? cfg.include_file_types.map((v) => String(v || '').toLowerCase())
  : ['text/html', 'application/pdf'];

const embeddingEnabled = cfg.embedding_enabled !== false;
const embeddingModel = String(cfg.embedding_model || 'govchat-embedding').trim() || 'govchat-embedding';
const embeddingMaxChars = Math.max(1000, Number.parseInt(String(cfg.embedding_max_chars || 8000), 10) || 8000);
const skipEmbeddingForUnchanged = cfg.skip_embedding_for_unchanged !== false;
const litellmUrl = String($env.LITELLM_URL || '').replace(/\/$/, '') + '/v1/embeddings';
const litellmKey = String($env.LITELLM_API_KEY || '').trim();
const cancelEndpointBase = String($env.CRAWLER_ADMIN_BASE_URL || 'http://govchat-overlay-admin:3002').replace(/\/$/, '');
const internalToken = String($env.CRAWLER_INTERNAL_TOKEN || $env.N8N_WEBHOOK_TOKEN || '').trim();
let cancelRequested = false;

const metrics = {
  visited_pages: 0,
  discovered_links: 0,
  robots_blocked: 0,
  outside_allowlist: 0,
  fetch_errors: 0,
  indexed_items: 0,
  embedding_calls: 0,
  embedding_errors: 0,
  embedding_skipped_unchanged: 0,
  changed_pages: 0,
  unchanged_pages: 0,
  seed_urls: 0,
  empty_seed_sources: 0,
};

const diagnostics = {
  ...(input.summary?.diagnostics || {}),
  reasons: [],
  source_start_candidates: [],
  runtime: {
    has_global_url: typeof URL === 'function',
    has_require: typeof require === 'function',
    has_abortsignal_timeout: typeof AbortSignal !== 'undefined' && typeof AbortSignal.timeout === 'function',
    has_fetch_global: typeof fetch === 'function',
  },
};

let URLCtor = null;
if (typeof URL === 'function') {
  URLCtor = URL;
} else {
  try {
    if (typeof require === 'function') {
      URLCtor = require('url').URL;
    }
  } catch (_) {
    URLCtor = null;
  }
}
diagnostics.runtime.has_url_ctor = Boolean(URLCtor);

let fetchFn = typeof fetch === 'function' ? fetch : null;
if (!fetchFn) {
  try {
    if (typeof require === 'function') {
      const nf = require('node-fetch');
      fetchFn = typeof nf === 'function' ? nf : nf?.default || null;
    }
  } catch (_) {
    // ignore
  }
}
if (!fetchFn) {
  try {
    if (typeof require === 'function') {
      const undici = require('undici');
      if (typeof undici?.fetch === 'function') fetchFn = undici.fetch;
    }
  } catch (_) {
    // ignore
  }
}
diagnostics.runtime.has_fetch_fn = Boolean(fetchFn);

let httpMod = null;
let httpsMod = null;
if (!fetchFn) {
  try {
    if (typeof require === 'function') {
      httpMod = require('http');
      httpsMod = require('https');
    }
  } catch (_) {
    httpMod = null;
    httpsMod = null;
  }
}
diagnostics.runtime.has_http_builtin = Boolean(httpMod && httpsMod);

function fetchWithHttpModules(url, options = {}, redirectDepth = 0) {
  return new Promise((resolve, reject) => {
    const parsed = parseUrlParts(url);
    if (!parsed) return reject(new Error('Invalid URL: ' + String(url || '')));
    const lib = parsed.protocol === 'https:' ? httpsMod : httpMod;
    if (!lib) return reject(new Error('HTTP modules are not available'));

    const requestOptions = {
      method: String(options.method || 'GET').toUpperCase(),
      headers: {
        ...(options.headers || {}),
        'accept-encoding': 'identity',
      },
    };

    const req = lib.request(parsed.href, requestOptions, (res) => {
      const status = Number(res.statusCode || 0);
      const headers = res.headers || {};

      if (status >= 300 && status < 400 && headers.location) {
        if (redirectDepth >= 5) {
          res.resume();
          return reject(new Error('Too many redirects'));
        }
        const nextUrl = normalizeUrl(String(headers.location), parsed.href);
        res.resume();
        if (!nextUrl) return reject(new Error('Invalid redirect location'));
        return resolve(fetchWithHttpModules(nextUrl, options, redirectDepth + 1));
      }

      const chunks = [];
      res.on('data', (chunk) => chunks.push(Buffer.from(chunk)));
      res.on('end', () => {
        const body = Buffer.concat(chunks).toString('utf-8');
        resolve({
          ok: status >= 200 && status < 300,
          status,
          headers: {
            get: (name) => {
              const key = String(name || '').toLowerCase();
              const val = headers[key];
              if (Array.isArray(val)) return val.join(', ');
              return val == null ? null : String(val);
            },
          },
          text: async () => body,
          json: async () => {
            try {
              return body ? JSON.parse(body) : {};
            } catch {
              return { raw: body };
            }
          },
        });
      });
      res.on('error', reject);
    });

    req.on('error', reject);

    if (options.signal && typeof options.signal.addEventListener === 'function') {
      const onAbort = () => {
        req.destroy(new Error('Request aborted'));
      };
      options.signal.addEventListener('abort', onAbort, { once: true });
    }

    if (options.body) req.write(String(options.body));
    req.end();
  });
}

if (!fetchFn && httpMod && httpsMod) {
  fetchFn = (url, options) => fetchWithHttpModules(url, options || {});
  diagnostics.runtime.has_fetch_fn = true;
}

function timeoutSignal(ms) {
  try {
    if (typeof AbortSignal !== 'undefined' && typeof AbortSignal.timeout === 'function') {
      return AbortSignal.timeout(ms);
    }
  } catch (_) {
    // ignore and run without abort signal
  }
  return undefined;
}

const visited = new Set();
const robotsCache = new Map();
let globalCount = 0;

function normalizeUrl(raw, base) {
  const inputRaw = String(raw || '').trim();
  if (!inputRaw) return null;

  const toPath = (p) => {
    const src = String(p || '/');
    const parts = src.split('/');
    const out = [];
    for (const part of parts) {
      if (!part || part === '.') continue;
      if (part === '..') {
        if (out.length) out.pop();
        continue;
      }
      out.push(part);
    }
    return '/' + out.join('/');
  };

  const parseSimple = (abs) => {
    const m = String(abs || '').trim().match(/^https?:\/\/([^\/?#\s]+)([^?#\s]*)?(\?[^#\s]*)?(#.*)?$/i);
    if (!m) return null;
    const hostRaw = String(m[1] || '').trim();
    if (!hostRaw) return null;
    const host = hostRaw.toLowerCase();
    const hostname = host.split(':')[0];
    const pathname = toPath(m[2] || '/');
    const query = m[3] || '';
    return {
      protocol: abs.toLowerCase().startsWith('https://') ? 'https:' : 'http:',
      host,
      hostname,
      pathname,
      href: `${abs.toLowerCase().startsWith('https://') ? 'https' : 'http'}://${host}${pathname}${query}`,
    };
  };

  try {
    if (URLCtor) {
      const u = base ? new URLCtor(inputRaw, base) : new URLCtor(inputRaw);
      if (!['http:', 'https:'].includes(u.protocol)) return null;
      u.hash = '';
      return u.toString();
    }
  } catch {
    // fallback hieronder
  }

  const absolute = /^https?:\/\//i.test(inputRaw);
  if (absolute) {
    const p = parseSimple(inputRaw);
    return p ? p.href : null;
  }

  const baseNorm = String(base || '').trim();
  const bp = parseSimple(baseNorm);
  if (!bp) return null;

  if (inputRaw.startsWith('//')) {
    const p = parseSimple(`${bp.protocol}${inputRaw}`);
    return p ? p.href : null;
  }

  if (inputRaw.startsWith('/')) {
    return `${bp.protocol}//${bp.host}${toPath(inputRaw)}`;
  }

  const baseDir = bp.pathname.endsWith('/')
    ? bp.pathname
    : (bp.pathname.slice(0, bp.pathname.lastIndexOf('/') + 1) || '/');
  return `${bp.protocol}//${bp.host}${toPath(baseDir + inputRaw)}`;
}

function parseUrlParts(raw, base) {
  const normalized = normalizeUrl(raw, base);
  if (!normalized) return null;

  if (URLCtor) {
    try {
      const u = new URLCtor(normalized);
      return {
        href: u.toString(),
        protocol: u.protocol,
        host: u.host.toLowerCase(),
        hostname: u.hostname.toLowerCase(),
        pathname: u.pathname || '/',
      };
    } catch (_) {
      // fallback below
    }
  }

  const m = normalized.match(/^https?:\/\/([^\/?#\s]+)([^?#\s]*)?/i);
  if (!m) return null;
  const host = String(m[1] || '').toLowerCase();
  const pathname = String(m[2] || '/');
  return {
    href: normalized,
    protocol: normalized.toLowerCase().startsWith('https://') ? 'https:' : 'http:',
    host,
    hostname: host.split(':')[0],
    pathname: pathname || '/',
  };
}

function urlAllowed(url, source) {
  const u = parseUrlParts(url);
  if (!u) return false;
  const host = u.hostname.toLowerCase();
  const path = u.pathname || '/';

  const domains = Array.isArray(source.allowed_domains) ? source.allowed_domains.map((d) => String(d || '').toLowerCase()).filter(Boolean) : [];
  const hostAllowed = domains.some((d) => host === d || (source.include_subdomains !== false && host.endsWith('.' + d)));
  if (!hostAllowed) return false;

  const prefixes = Array.isArray(source.allowed_path_prefixes) ? source.allowed_path_prefixes : ['/'];
  return prefixes.some((p) => {
    const pref = String(p || '/').trim() || '/';
    return path.startsWith(pref);
  });
}

function parseRobotsTxt(content) {
  const lines = String(content || '').split(/\r?\n/);
  const blocks = [];
  let current = null;

  for (const lineRaw of lines) {
    const line = lineRaw.split('#')[0].trim();
    if (!line) continue;
    const idx = line.indexOf(':');
    if (idx < 0) continue;
    const key = line.slice(0, idx).trim().toLowerCase();
    const value = line.slice(idx + 1).trim();

    if (key === 'user-agent') {
      current = { agent: value.toLowerCase(), disallow: [], allow: [] };
      blocks.push(current);
      continue;
    }

    if (!current) continue;
    if (key === 'disallow') current.disallow.push(value || '/');
    if (key === 'allow') current.allow.push(value || '/');
  }

  const selected = blocks.filter((b) => b.agent === '*' || userAgent.toLowerCase().includes(b.agent));
  const disallow = [];
  const allow = [];
  for (const b of selected) {
    for (const d of b.disallow || []) disallow.push(d);
    for (const a of b.allow || []) allow.push(a);
  }
  return { disallow, allow };
}

function robotsAllows(url, policy) {
  if (!policy) return true;
  const parts = parseUrlParts(url);
  if (!parts) return false;
  const path = parts.pathname || '/';
  let blocked = false;
  for (const d of policy.disallow || []) {
    if (!d || d === '') continue;
    if (path.startsWith(d)) blocked = true;
  }
  if (!blocked) return true;
  for (const a of policy.allow || []) {
    if (!a || a === '') continue;
    if (path.startsWith(a)) return true;
  }
  return false;
}

function extractLinks(html, baseUrl) {
  const links = new Set();
  const regex = /href\s*=\s*['\"]([^'\"#]+)['\"]/gi;
  let m;
  while ((m = regex.exec(String(html || '')))) {
    const n = normalizeUrl(m[1], baseUrl);
    if (n) links.add(n);
  }
  return [...links];
}

function extractSitemapUrls(xml) {
  const out = [];
  const regex = /<loc>([^<]+)<\/loc>/gi;
  let m;
  while ((m = regex.exec(String(xml || '')))) {
    const n = normalizeUrl(m[1]);
    if (n) out.push(n);
  }
  return out;
}

function scoreUrl(url) {
  if (url.includes('.pdf')) return 2;
  if (url.endsWith('/')) return 1;
  return 0;
}

function stripHtml(html) {
  return String(html || '')
    .replace(/<script[\s\S]*?<\/script>/gi, ' ')
    .replace(/<style[\s\S]*?<\/style>/gi, ' ')
    .replace(/<[^>]+>/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function estimateTokens(text) {
  const chars = String(text || '').length;
  return Math.max(1, Math.ceil(chars / 4));
}

function hostGroup(host) {
  const parts = String(host || '').toLowerCase().split('.').filter(Boolean);
  if (parts.length <= 2) return host;
  return parts.slice(parts.length - 2).join('.');
}

function stableHash(inputText) {
  const text = String(inputText || '');
  let h = 0x811c9dc5;
  for (let i = 0; i < text.length; i += 1) {
    h ^= text.charCodeAt(i);
    h += (h << 1) + (h << 4) + (h << 7) + (h << 8) + (h << 24);
  }
  return (h >>> 0).toString(16).padStart(8, '0');
}

function contentSignature(contentTypeMain, textForEmbedding) {
  return 'v1:' + stableHash(`${String(contentTypeMain || 'unknown')}\n${String(textForEmbedding || '')}`);
}

function parseTimestamp(inputValue) {
  const ts = Date.parse(String(inputValue || '').trim());
  return Number.isNaN(ts) ? 0 : ts;
}

async function fetchText(url, accept) {
  if (!fetchFn) throw new Error('fetch is not available in n8n code runner');
  const signal = timeoutSignal(timeoutMs);
  const res = await fetchFn(url, {
    method: 'GET',
    headers: {
      'user-agent': userAgent,
      accept: accept || '*/*',
    },
    ...(signal ? { signal } : {}),
  });
  if (!res.ok) throw new Error('HTTP ' + res.status + ' for ' + url);
  const contentType = String(res.headers.get('content-type') || '').toLowerCase();
  const body = await res.text();
  return { body, contentType };
}

async function embedText(text) {
  if (!embeddingEnabled || !litellmKey || !litellmUrl.startsWith('http')) {
    return { status: embeddingEnabled ? 'not-configured' : 'disabled', usage: null };
  }

  const payload = {
    model: embeddingModel,
    input: text,
  };

  if (!fetchFn) throw new Error('fetch is not available in n8n code runner');
  const signal = timeoutSignal(timeoutMs);
  const res = await fetchFn(litellmUrl, {
    method: 'POST',
    headers: {
      'content-type': 'application/json',
      authorization: 'Bearer ' + litellmKey,
    },
    body: JSON.stringify(payload),
    ...(signal ? { signal } : {}),
  });

  const raw = await res.text();
  let parsed = {};
  try {
    parsed = raw ? JSON.parse(raw) : {};
  } catch {
    parsed = { raw };
  }

  if (!res.ok) {
    const msg = String(parsed?.error?.message || parsed?.error || parsed?.message || raw || '').trim();
    throw new Error(msg || ('Embedding HTTP ' + res.status));
  }

  return {
    status: 'ok',
    usage: parsed?.usage || null,
  };
}

async function checkCancelled() {
  if (!input.run_id || !internalToken) return false;
  if (!fetchFn) return false;
  try {
    const url = cancelEndpointBase + '/api/crawler/internal/runs/' + encodeURIComponent(String(input.run_id)) + '/cancelled';
    const signal = timeoutSignal(timeoutMs);
    const res = await fetchFn(url, {
      method: 'GET',
      headers: { 'x-govchat-token': internalToken },
      ...(signal ? { signal } : {}),
    });
    if (!res.ok) return false;
    const body = await res.json();
    return body?.cancel_requested === true;
  } catch (_) {
    return false;
  }
}

async function loadLatestPageSnapshotMap() {
  const pageMap = new Map();
  if (!internalToken || !fetchFn) return pageMap;

  try {
    const url = cancelEndpointBase + '/api/crawler/internal/runs?limit=200';
    const signal = timeoutSignal(timeoutMs);
    const res = await fetchFn(url, {
      method: 'GET',
      headers: { 'x-govchat-token': internalToken },
      ...(signal ? { signal } : {}),
    });
    if (!res.ok) return pageMap;

    let payload = {};
    if (typeof res.json === 'function') {
      payload = await res.json();
    } else {
      const raw = await res.text();
      try {
        payload = raw ? JSON.parse(raw) : {};
      } catch {
        payload = {};
      }
    }

    const runs = Array.isArray(payload?.runs) ? payload.runs : [];
    for (const run of runs) {
      const runTs = parseTimestamp(run?.finished_at || run?.started_at);
      const pages = Array.isArray(run?.indexed_pages) ? run.indexed_pages : [];
      for (const page of pages) {
        const normalizedUrl = normalizeUrl(page?.url);
        if (!normalizedUrl) continue;

        const pageTs = parseTimestamp(page?.verified_at || page?.indexed_at) || runTs;
        const known = pageMap.get(normalizedUrl);
        if (known && known.ts > pageTs) continue;

        pageMap.set(normalizedUrl, {
          ts: pageTs,
          signature: String(page?.content_signature || '').trim(),
          content_updated_at: String(page?.content_updated_at || page?.indexed_at || run?.finished_at || '').trim() || null,
          verified_at: String(page?.verified_at || page?.indexed_at || run?.finished_at || '').trim() || null,
          total_tokens: Number(page?.total_tokens || page?.input_tokens_est || 0),
        });
      }
    }
  } catch (_) {
    return pageMap;
  }

  return pageMap;
}

const indexed_pages = [];
const token_usage = {
  model: embeddingModel,
  total_input_tokens_est: 0,
  total_prompt_tokens: 0,
  total_tokens: 0,
  by_domain: {},
  by_subwebsite: {},
};
const previousPagesByUrl = await loadLatestPageSnapshotMap();
diagnostics.previous_snapshot_urls = previousPagesByUrl.size;
diagnostics.skip_embedding_for_unchanged = skipEmbeddingForUnchanged;

for (const source of sources) {
  if (cancelRequested) break;
  const queue = [];
  const sourceSeen = new Set();

  const rawStart = String(
    source.start_url || source.startUrl || source.url || source.homepage || ''
  ).trim();
  diagnostics.source_start_candidates.push({
    source_id: String(source.id || ''),
    source_name: String(source.name || ''),
    raw_start: rawStart,
  });

  const start = normalizeUrl(rawStart);
  if (start) queue.push({ url: start, depth: 0 });

  if ((!Array.isArray(source.allowed_domains) || !source.allowed_domains.length) && start) {
    const startParts = parseUrlParts(start);
    source.allowed_domains = startParts?.hostname ? [startParts.hostname.toLowerCase()] : [];
  }

  const sitemaps = Array.isArray(source.sitemap_urls) && source.sitemap_urls.length
    ? source.sitemap_urls
    : [normalizeUrl('/sitemap.xml', source.start_url)].filter(Boolean);

  for (const sm of sitemaps) {
    try {
      const { body } = await fetchText(sm, 'application/xml,text/xml;q=0.9,*/*;q=0.8');
      const entries = extractSitemapUrls(body)
        .filter((u) => urlAllowed(u, source))
        .sort((a, b) => scoreUrl(b) - scoreUrl(a));
      for (const u of entries.slice(0, source.max_pages)) {
        if (!sourceSeen.has(u)) {
          sourceSeen.add(u);
          queue.push({ url: u, depth: 0 });
        }
      }
    } catch (_) {
      // sitemap optioneel; doorgaan met start_url crawl
    }
  }

  metrics.seed_urls += queue.length;
  if (!queue.length) {
    metrics.empty_seed_sources += 1;
    diagnostics.reasons.push(
      `Geen seed-URL voor bron '${String(source.name || source.id || source.start_url || source.startUrl || 'onbekend')}'`
    );
  }

  let cursor = 0;
  while (cursor < queue.length) {
    if (globalCount >= maxPagesGlobal) break;
    if (metrics.visited_pages >= maxPagesGlobal) break;

    const item = queue[cursor++];
    if (!item || !item.url) continue;
    if (item.depth > source.max_depth) continue;
    if (visited.has(item.url)) continue;

    if (await checkCancelled()) {
      cancelRequested = true;
      break;
    }

    if (!urlAllowed(item.url, source)) {
      metrics.outside_allowlist += 1;
      continue;
    }

      if (respectRobots) {
        let robotsPolicy = null;
        try {
          const itemParts = parseUrlParts(item.url);
          const host = itemParts?.host || '';
          if (!host) throw new Error('invalid item host');
          if (robotsCache.has(host)) {
            robotsPolicy = robotsCache.get(host);
          } else {
            const ru = normalizeUrl('/robots.txt', item.url);
            if (!ru) throw new Error('invalid robots url');
            const { body } = await fetchText(ru, 'text/plain,*/*;q=0.5');
            robotsPolicy = parseRobotsTxt(body);
            robotsCache.set(host, robotsPolicy);
        }
      } catch (_) {
        // als robots.txt niet leesbaar is: fail-open om publieke overheidssites niet onnodig te blokkeren
      }

      if (!robotsAllows(item.url, robotsPolicy)) {
        metrics.robots_blocked += 1;
        continue;
      }
    }

    try {
      const { body, contentType } = await fetchText(item.url, 'text/html,application/pdf,application/xhtml+xml;q=0.9,*/*;q=0.5');
      visited.add(item.url);
      globalCount += 1;
      metrics.visited_pages += 1;

      const contentTypeMain = String(contentType || '').split(';')[0].trim().toLowerCase();
      const typeAllowed = includeFileTypes.some((t) => contentTypeMain.startsWith(String(t).toLowerCase()));
      if (!typeAllowed) {
        continue;
      }

      const isHtml = contentType.includes('text/html') || contentType.includes('application/xhtml+xml');
      const textRaw = isHtml ? stripHtml(body) : String(body || '').replace(/\s+/g, ' ').trim();
      const textForEmbedding = textRaw.slice(0, embeddingMaxChars);
      const signature = contentSignature(contentTypeMain || 'unknown', textForEmbedding);
      const inputTokensEst = estimateTokens(textForEmbedding);
      const nowIso = new Date().toISOString();
      const normalizedItemUrl = normalizeUrl(item.url) || item.url;
      const previousPage = previousPagesByUrl.get(normalizedItemUrl) || null;
      const changed = !previousPage || !previousPage.signature || previousPage.signature !== signature;
      const verifiedAt = nowIso;
      const contentUpdatedAt = changed
        ? nowIso
        : String(previousPage?.content_updated_at || previousPage?.verified_at || nowIso);

      let promptTokens = 0;
      let totalTokens = inputTokensEst;
      let embeddingStatus = 'disabled';

      if (changed) metrics.changed_pages += 1;
      else metrics.unchanged_pages += 1;

      try {
        if (textForEmbedding) {
          if (!changed && skipEmbeddingForUnchanged) {
            embeddingStatus = 'skipped_unchanged';
            promptTokens = 0;
            totalTokens = 0;
            metrics.embedding_skipped_unchanged += 1;
          } else {
            const emb = await embedText(textForEmbedding);
            embeddingStatus = emb.status;
            if (emb.status === 'ok') {
              metrics.embedding_calls += 1;
              promptTokens = Number(emb.usage?.prompt_tokens || inputTokensEst || 0);
              totalTokens = Number(emb.usage?.total_tokens || promptTokens || inputTokensEst || 0);
            }
          }
        }
      } catch (err) {
        embeddingStatus = 'error';
        metrics.embedding_errors += 1;
      }

      const u = parseUrlParts(item.url);
      if (!u) {
        metrics.fetch_errors += 1;
        continue;
      }
      const domain = hostGroup(u.hostname);
      const subwebsite = u.hostname.toLowerCase();

      const page = {
        source_id: source.id,
        source_name: source.name,
        url: item.url,
        domain,
        subwebsite,
        path: u.pathname || '/',
        verified_at: verifiedAt,
        indexed_at: nowIso,
        content_updated_at: contentUpdatedAt,
        content_signature: signature,
        is_changed: changed,
        content_type: contentTypeMain || 'unknown',
        chars_indexed: textForEmbedding.length,
        input_tokens_est: inputTokensEst,
        prompt_tokens: promptTokens,
        total_tokens: totalTokens,
        embedding_model: embeddingModel,
        embedding_status: embeddingStatus,
      };

      indexed_pages.push(page);
      metrics.indexed_items += 1;
      previousPagesByUrl.set(normalizedItemUrl, {
        ts: parseTimestamp(verifiedAt),
        signature,
        content_updated_at: contentUpdatedAt,
        verified_at: verifiedAt,
        total_tokens: totalTokens,
      });

      token_usage.total_input_tokens_est += inputTokensEst;
      token_usage.total_prompt_tokens += promptTokens;
      token_usage.total_tokens += totalTokens;

      if (!token_usage.by_domain[domain]) {
        token_usage.by_domain[domain] = { pages: 0, total_tokens: 0, prompt_tokens: 0, input_tokens_est: 0 };
      }
      token_usage.by_domain[domain].pages += 1;
      token_usage.by_domain[domain].total_tokens += totalTokens;
      token_usage.by_domain[domain].prompt_tokens += promptTokens;
      token_usage.by_domain[domain].input_tokens_est += inputTokensEst;

      if (!token_usage.by_subwebsite[subwebsite]) {
        token_usage.by_subwebsite[subwebsite] = { pages: 0, total_tokens: 0, prompt_tokens: 0, input_tokens_est: 0 };
      }
      token_usage.by_subwebsite[subwebsite].pages += 1;
      token_usage.by_subwebsite[subwebsite].total_tokens += totalTokens;
      token_usage.by_subwebsite[subwebsite].prompt_tokens += promptTokens;
      token_usage.by_subwebsite[subwebsite].input_tokens_est += inputTokensEst;

      if (isHtml) {
        const links = extractLinks(body, item.url);
        for (const link of links) {
          if (!urlAllowed(link, source)) {
            metrics.outside_allowlist += 1;
            continue;
          }
          if (!sourceSeen.has(link) && !visited.has(link) && item.depth + 1 <= source.max_depth) {
            sourceSeen.add(link);
            queue.push({ url: link, depth: item.depth + 1 });
            metrics.discovered_links += 1;
          }
        }
      }

      if (metrics.visited_pages >= source.max_pages) break;
    } catch (err) {
      metrics.fetch_errors += 1;
      if (!diagnostics.first_fetch_error) {
        diagnostics.first_fetch_error = {
          name: String(err?.name || 'Error'),
          message: String(err?.message || err || 'Onbekende fetch-fout'),
        };
      }
    }
  }
}

const finalStatus = cancelRequested ? 'cancelled' : 'finished';
const finishedAt = new Date().toISOString();

return [{
  json: {
    ...input,
    skip_run: false,
    status: finalStatus,
    finished_at: finishedAt,
    summary: {
      ...(input.summary || {}),
      ...metrics,
      cancel_requested: cancelRequested,
      diagnostics,
      warning: metrics.visited_pages === 0
        ? (diagnostics.first_fetch_error?.message
            ? `Fetch-fout: ${diagnostics.first_fetch_error.message}`
            : diagnostics.reasons.length
            ? diagnostics.reasons.join(' | ')
            : 'Geen pagina\'s bezocht. Controleer start_url, domein allowlist en robots.txt')
        : null,
    },
    indexed_pages,
    token_usage,
  },
}];
